let tw=null;const TW_FROM=process.env.TWILIO_WHATSAPP_FROM||'whatsapp:+14155238886';
try{if(process.env.TWILIO_ACCOUNT_SID&&process.env.TWILIO_AUTH_TOKEN){tw=twilio(process.env.TWILIO_ACCOUNT_SID,process.env.TWILIO_AUTH_TOKEN);console.log('✅ Twilio connected')}}catch(e){console.log('⚠️',e.message)}

const genId=()=>'t_'+Date.now()+'_'+Math.random().toString(36).slice(2,8);
const genToken=()=>crypto.randomBytes(32).toString('hex');
const _secureCookie=process.env.NODE_ENV==='production'||process.env.RAILWAY_ENVIRONMENT?'; Secure':'';
const setTokenCookie=(res,token)=>{const maxAge=365*24*60*60;res.append('Set-Cookie','tf_token='+encodeURIComponent(token)+'; Path=/; Max-Age='+maxAge+'; SameSite=Lax; HttpOnly'+_secureCookie)};
const genOTP=()=>String(Math.floor(100000+Math.random()*900000));
const PRI={high:'🔴',medium:'🟠',low:'🟢'};
const fmtD=d=>d?new Date(d+'T00:00:00').toLocaleDateString('en-US',{month:'short',day:'numeric'}):'';
const todayStr=()=>new Date().toISOString().split('T')[0];
const cleanPhone=p=>{let c=(p||'').replace(/[^0-9+]/g,'');if(!c.startsWith('+'))c='+'+c;return c};
function looksLikeMissingCountryCode(p){
  // Heuristic: 10 digits without + and starting with a non-1, non-7-9 digit isn't a country code.
  // If user types exactly 10 digits we suspect missing country code.
  const digits=(p||'').replace(/[^0-9]/g,'');
  return digits.length===10;
}

async function sendWA(to,body){
  if(!tw)return{ok:false,reason:'Twilio not configured',code:'NO_TWILIO'};
  try{const n=to.startsWith('whatsapp:')?to:'whatsapp:'+to;const m=await tw.messages.create({from:TW_FROM,to:n,body});return{ok:true,sid:m.sid,status:m.status}}catch(e){return{ok:false,reason:e.message||String(e),code:e.code||0,moreInfo:e.moreInfo||''}}
}
function waErrorMessage(r){
  const c=r.code;
  if(c===21211||c===21214||c===21217)return 'Phone number format is invalid. Include the country code (e.g. +91 9876543210 for India).';
  if(c===63007)return 'WhatsApp number not registered for this account.';
  if(c===63015||c===63016)return 'WhatsApp link to BroDoit has expired. Tap "Re-send join code" below to refresh it (links expire after 72h of inactivity).';
  if(c===63018)return 'Daily message limit reached. Try again in a few hours or use email login.';
  if(c===21610)return 'This number opted out of BroDoit messages. Tap "Re-send join code" below to opt back in.';
  return 'WhatsApp delivery failed. Tap "Re-send join code" below \\u2014 you may need to reconnect to BroDoit on WhatsApp.';
}

// Email via Resend (free tier: 3000/mo, 100/day)
const EMAIL_FROM=process.env.EMAIL_FROM||'Brodoit <onboarding@resend.dev>';
async function sendEmail(to,subject,html){
  if(!process.env.RESEND_API_KEY)return{ok:false,reason:'RESEND_API_KEY not set'};
  try{
    const r=await fetch('https://api.resend.com/emails',{method:'POST',headers:{'Authorization':'Bearer '+process.env.RESEND_API_KEY,'Content-Type':'application/json'},body:JSON.stringify({from:EMAIL_FROM,to:[to],subject,html})});
    if(!r.ok){const err=await r.text();return{ok:false,reason:err}}
    return{ok:true}
  }catch(e){return{ok:false,reason:e.message}}
}
const isEmail=s=>/^[\w.+-]+@[\w-]+\.[a-z]{2,}$/i.test(s||'');

// Simple per-identifier rate limiter (max 3 requests per 10 min)
const _otpAttempts=new Map();
function rateLimited(identifier){
  const now=Date.now();
  const list=(_otpAttempts.get(identifier)||[]).filter(t=>now-t<10*60*1000);
  if(list.length>=3)return true;
  list.push(now);_otpAttempts.set(identifier,list);
  return false;
}

// Throttle last_seen writes to once per 60s per user — avoid hammering the
// DB on every API call (which fires every few seconds on the home tab).
const _lastSeenCache=new Map();
function auth(req,res,next){
  let t=req.headers['x-token']||String(req.query&&req.query.token||'').trim()||'';
  if(!t){try{const c=(req.headers.cookie||'');const m=c.match(/tf_token=([^;]+)/);if(m)t=decodeURIComponent(m[1])}catch(e){}}
  if(!t)return res.status(401).json({error:'Login required'});
  const u=db.prepare('SELECT * FROM users WHERE token=?').get(t);if(!u)return res.status(401).json({error:'Invalid token'});
  req.user=u;
  // Auto-save user timezone from browser
  const ctz=req.headers['x-timezone']||'';
  if(ctz&&ctz!==u.tz&&/^[A-Za-z_\/]+$/.test(ctz)){try{db.prepare('UPDATE users SET tz=? WHERE phone=?').run(ctz,u.phone);u.tz=ctz}catch(e){}}
  try{const now=Date.now();const cached=_lastSeenCache.get(u.phone)||0;if(now-cached>60000){_lastSeenCache.set(u.phone,now);db.prepare("UPDATE users SET last_seen=datetime('now') WHERE phone=?").run(u.phone)}}catch(e){}
  next();
}
function _getUserTz(userPhone){
  try{const r=db.prepare('SELECT tz FROM users WHERE phone=?').get(userPhone);return(r&&r.tz)||'UTC'}catch(e){return'UTC'}
}

// Admin auth — gates the tester dashboards. Three ways to authenticate
// (in priority order):
//   1. ?token= matches ADMIN_TOKEN env var
//   2. logged-in user's email matches ADMIN_EMAIL env var
//   3. fallback: logged-in user is the FIRST account ever created on this DB
//      (the original developer account — works without any env vars set)
const ADMIN_TOKEN=process.env.ADMIN_TOKEN||'';
const ADMIN_EMAIL=(process.env.ADMIN_EMAIL||'').toLowerCase();
function _isFirstAccountUser(t){
  if(!t)return false;
  try{
    const u=db.prepare('SELECT email,created_at FROM users WHERE token=?').get(t);
    if(!u||!u.email)return false;
    const first=db.prepare("SELECT email FROM users WHERE email IS NOT NULL AND email!='' ORDER BY created_at ASC LIMIT 1").get();
    return first&&first.email===u.email;
  }catch(e){return false}
}
function adminAuth(req,res,next){
  const provided=String(req.query.token||req.headers['x-admin-token']||'').trim();
  if(ADMIN_TOKEN&&provided===ADMIN_TOKEN)return next();
  const t=String(req.headers['x-token']||req.query.x_token||'').trim();
  if(t&&ADMIN_EMAIL){
    const u=db.prepare('SELECT email FROM users WHERE token=?').get(t);
    if(u&&(u.email||'').toLowerCase()===ADMIN_EMAIL)return next();
  }
  // Bootstrap fallback: first registered account on this DB (= the developer)
  if(_isFirstAccountUser(t))return next();
  // If accessed from a browser (no token at all), inject a bootstrap script
  // that reads the user's login token from localStorage and re-requests the
  // same URL with ?x_token=. If they're signed in to Brodoit in the same
  // browser, they'll land on the dashboard instantly. If not, they see the
  // "Sign in first" card with a clear next step.
  if(!provided&&!t&&req.headers.accept&&req.headers.accept.includes('text/html')){
    return res.status(200).type('html').send(`<!doctype html><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Brodoit · Admin</title><script>(function(){try{var t=localStorage.getItem('tf_token');if(t){var sep=location.search?'&':'?';location.replace(location.pathname+sep+'x_token='+encodeURIComponent(t)+(location.search?'&'+location.search.substr(1):''));}else{document.body.innerHTML='<div class="card"><h1>Sign in first</h1><p>Open Brodoit, sign in with your developer email, then return here in the same browser.</p><a href="/">Open Brodoit \\u2192</a></div>';}}catch(e){document.body.innerHTML='<div class="card"><h1>Sign in first</h1><p>Open Brodoit and sign in.</p><a href="/">Open Brodoit \\u2192</a></div>';}})();</script><style>body{font-family:-apple-system,Segoe UI,sans-serif;background:#0F1115;color:#FFD27A;display:grid;place-items:center;min-height:100vh;margin:0;padding:24px;text-align:center;line-height:1.6}.card{max-width:420px;background:#3A2D22;border:1px solid rgba(255,210,122,.15);border-radius:18px;padding:36px 28px}h1{font-family:Georgia,serif;font-weight:400;font-size:28px;margin:0 0 8px}p{color:rgba(255,210,122,.65);font-size:14px;margin:0 0 22px}a{display:inline-block;padding:13px 24px;background:#FFD27A;color:#0F1115;text-decoration:none;border-radius:10px;font-weight:600;font-size:14px}</style>`);
  }
  return res.status(401).send('Unauthorized');
}

// GET /admin/testers — HTML dashboard showing every user, when they signed
// up, when they were last seen, and whether they cross the 14-day mark.
// Use to track Play Store closed-test progress.
app.get('/admin/testers',adminAuth,(req,res)=>{
  const rows=db.prepare("SELECT phone,name,email,is_beta_tester,created_at,last_seen FROM users ORDER BY created_at DESC").all();
  const now=Date.now();
  const escH=s=>(s||'').replace(/[<>&]/g,c=>({'<':'&lt;','>':'&gt;','&':'&amp;'})[c]);
  const fmtAgo=ts=>{if(!ts)return '<span style="color:#B5A898">never</span>';const t=new Date(ts.replace(' ','T')+'Z').getTime();const m=Math.floor((now-t)/60000);if(m<2)return 'just now';if(m<60)return m+'m ago';const h=Math.floor(m/60);if(h<24)return h+'h ago';const d=Math.floor(h/24);return d+'d ago'};
  const days=ts=>{if(!ts)return 0;return Math.floor((now-new Date(ts.replace(' ','T')+'Z').getTime())/86400000)};
  const total=rows.length;
  const eligible=rows.filter(r=>r.last_seen&&days(r.created_at)>=14&&days(r.last_seen)<=2).length;
  const tableRows=rows.map((r,i)=>{
    const seenDays=r.last_seen?days(r.last_seen):null;
    const memberDays=days(r.created_at);
    const status=memberDays>=14&&seenDays!=null&&seenDays<=2?'✅ 14-day':memberDays<14?'⏱ day '+memberDays+'/14':seenDays>2?'⚠️ lapsed':'⏱';
    const statusColor=memberDays>=14&&seenDays!=null&&seenDays<=2?'#C47A3A':seenDays>2?'#DC2626':'#D97706';
    return `<tr style="border-bottom:1px solid #E8E0D4"><td style="padding:10px 8px">${i+1}</td><td style="padding:10px 8px;font-weight:600">${escH(r.name||'—')}</td><td style="padding:10px 8px;color:#9C8B7A;font-family:monospace;font-size:12px">${escH(r.email||r.phone)}</td><td style="padding:10px 8px;color:#9C8B7A">${memberDays}d ago</td><td style="padding:10px 8px">${fmtAgo(r.last_seen)}</td><td style="padding:10px 8px;color:${statusColor};font-weight:600">${status}</td></tr>`;
  }).join('');
  res.send(`<!doctype html><html><head><title>Brodoit · Testers</title><meta name="viewport" content="width=device-width,initial-scale=1"><style>body{font-family:-apple-system,Segoe UI,sans-serif;background:#FBF7F1;color:#3A2D22;margin:0;padding:24px;max-width:980px;margin:0 auto}h1{font-size:22px;margin:0 0 6px}.sub{color:#9C8B7A;font-size:13px;margin-bottom:24px}.cards{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:12px;margin-bottom:24px}.card{background:#fff;border:1px solid #E8E0D4;border-radius:12px;padding:16px}.card .v{font-size:32px;font-weight:700;letter-spacing:-.02em}.card .l{font-size:12px;color:#9C8B7A;margin-top:4px;text-transform:uppercase;letter-spacing:.04em;font-weight:600}table{width:100%;border-collapse:collapse;background:#fff;border:1px solid #E8E0D4;border-radius:12px;overflow:hidden}th{text-align:left;padding:12px 8px;background:#FBF7F1;font-size:11px;text-transform:uppercase;letter-spacing:.06em;color:#9C8B7A;font-weight:600;border-bottom:1px solid #E8E0D4}.note{margin-top:18px;padding:14px;background:#FDF8F3;border:1px solid #E8E0D4;border-radius:10px;font-size:13px;color:#C47A3A;line-height:1.5}</style></head><body><h1>Brodoit · Closed Test Dashboard</h1><div class="sub">Tester activity for Play Store 14-day requirement. Auto-refreshes when you reload.</div><div class="cards"><div class="card"><div class="v">${total}</div><div class="l">Total signups</div></div><div class="card"><div class="v" style="color:${eligible>=12?'#C47A3A':'#D97706'}">${eligible}</div><div class="l">14-day eligible</div></div><div class="card"><div class="v">${Math.max(0,12-eligible)}</div><div class="l">Still needed</div></div></div><table><thead><tr><th>#</th><th>Name</th><th>Login</th><th>Joined</th><th>Last seen</th><th>14-day status</th></tr></thead><tbody>${tableRows||'<tr><td colspan="6" style="padding:32px;text-align:center;color:#B5A898">No users yet</td></tr>'}</tbody></table><div class="note"><b>14-day eligibility</b> = user joined ≥14 days ago AND last seen within 2 days. Once <b>12 testers</b> are eligible, you can promote to production.</div></body></html>`);
});

