// ═══ AI CHAT — Multi-provider (Gemini Flash free → Groq free → failover) ═══
// API keys stay on the server. The browser never sees them.
const GEMINI_KEY=process.env.GEMINI_API_KEY||'';
const GROQ_KEY=process.env.GROQ_API_KEY||'';
console.log('[ai] gemini',GEMINI_KEY?'✅':'❌','groq',GROQ_KEY?'✅':'❌');

// ─── LLM Provider Abstraction ─────────────────────────────────────────────
// Tries providers in order: Gemini Flash (1500 req/day free) → Groq (30 RPM free)
// Each provider returns {reply:string} or throws on failure.
async function _callGemini(messages,{maxTokens=4096,systemPrompt=''}={}){
  if(!GEMINI_KEY)throw new Error('no-key');
  // Convert OpenAI-style messages to Gemini format
  const contents=messages.filter(m=>m.role!=='system').map(m=>({
    role:m.role==='assistant'?'model':'user',
    parts:[{text:m.content}]
  }));
  const body={contents,generationConfig:{maxOutputTokens:maxTokens,temperature:0.7}};
  if(systemPrompt)body.systemInstruction={parts:[{text:systemPrompt}]};
  const ctrl=new AbortController();const tmr=setTimeout(()=>ctrl.abort(),50000);
  try{
    const r=await fetch('https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key='+GEMINI_KEY,{
      method:'POST',signal:ctrl.signal,
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify(body)
    });
    clearTimeout(tmr);
    const j=await r.json();
    if(!r.ok){const msg=(j.error&&j.error.message)||'Gemini error';console.log('[ai] Gemini error:',r.status,msg);throw new Error(msg)}
    const text=j.candidates&&j.candidates[0]&&j.candidates[0].content&&j.candidates[0].content.parts&&j.candidates[0].content.parts[0]&&j.candidates[0].content.parts[0].text;
    if(!text)throw new Error('empty response');
    return{reply:text,provider:'gemini'};
  }catch(e){clearTimeout(tmr);throw e}
}

async function _callGroq(messages,{maxTokens=4096,tools}={}){
  if(!GROQ_KEY)throw new Error('no-key');
  const body={model:'llama-3.3-70b-versatile',max_tokens:maxTokens,messages};
  if(tools)body.tools=tools;
  let r,j;
  for(let retry=0;retry<3;retry++){
    const ctrl=new AbortController();const tmr=setTimeout(()=>ctrl.abort(),45000);
    try{
      r=await fetch('https://api.groq.com/openai/v1/chat/completions',{
        method:'POST',signal:ctrl.signal,
        headers:{'Content-Type':'application/json','Authorization':'Bearer '+GROQ_KEY},
        body:JSON.stringify(body)
      });
    }catch(fe){clearTimeout(tmr);if(retry<2){await new Promise(ok=>setTimeout(ok,2000*(retry+1)));continue}throw new Error('timeout')}
    clearTimeout(tmr);
    if(r.status===429||r.status>=500){
      if(retry<2){await new Promise(ok=>setTimeout(ok,2000*(retry+1)));continue}
    }
    break;
  }
  j=await r.json();
  if(!r.ok){const msg=(j.error&&j.error.message)||'Groq error';console.log('[ai] Groq error:',r.status,msg);throw new Error(msg)}
  const msg=j.choices&&j.choices[0]&&j.choices[0].message;
  return{reply:msg&&msg.content,message:msg,provider:'groq',usage:j.usage};
}

// Simple response cache (LRU, 200 entries, 10 min TTL)
const _aiCache=new Map();const _AI_CACHE_MAX=200;const _AI_CACHE_TTL=600000;
function _aiCacheKey(msgs){return msgs.slice(-3).map(m=>m.content||'').join('|').slice(0,300)}
function _aiCacheGet(key){const e=_aiCache.get(key);if(!e)return null;if(Date.now()-e.ts>_AI_CACHE_TTL){_aiCache.delete(key);return null}return e.reply}
function _aiCacheSet(key,reply){if(_aiCache.size>=_AI_CACHE_MAX){const first=_aiCache.keys().next().value;_aiCache.delete(first)}_aiCache.set(key,{reply,ts:Date.now()})}

const COACH_SYSTEM=`You are an expert Business English coach speaking with a fluent professional who wants to sound MORE polished and use more sophisticated vocabulary in business contexts.

When they say something, structure your reply in this exact short format:

1. Brief acknowledgment of what they said (one sentence)
2. A more polished/business-appropriate rewrite of their last sentence
3. ONE vocabulary or idiom tip relevant to it (a sophisticated word/phrase + meaning + how to use it)
4. A follow-up question that pushes the conversation forward

Keep total response under 90 words. Use sophisticated vocabulary yourself naturally — words like "leverage", "nuance", "cadence", "granular", "alignment", "downstream", "actionable", "stakeholder", "throughput", "paradigm", "by and large", "in lieu of", "tantamount to", "circle back", "drill down".

Be warm but direct. Never explain that you are an AI.`;

app.post('/api/coach/chat',auth,async(req,res)=>{
  if(!GROQ_KEY&&!GEMINI_KEY)return res.status(503).json({error:'AI coach not configured.'});
  const messages=Array.isArray(req.body&&req.body.messages)?req.body.messages.slice(-20):null;
  if(!messages||!messages.length)return res.status(400).json({error:'messages required'});
  const sys=req.body.system||COACH_SYSTEM;
  const apiMsgs=[{role:'system',content:sys},...messages.map(m=>({role:m.role==='assistant'?'assistant':'user',content:String(m.content||'').slice(0,4000)}))];
  try{
    let reply='';
    if(GEMINI_KEY){try{const g=await _callGemini(apiMsgs,{maxTokens:600,systemPrompt:sys});reply=g.reply}catch(e){}}
    if(!reply&&GROQ_KEY){try{const g=await _callGroq(apiMsgs,{maxTokens:600});reply=g.reply}catch(e){}}
    if(!reply)return res.status(502).json({error:'AI service busy — try again'});
    res.json({reply});
  }catch(e){res.status(500).json({error:String(e.message||e)})}
});

// ═══ BRO / BRI — Life Coach Chat (Groq free tier → Anthropic fallback) ═══
// ─── Bro agent tools ─────────────────────────────────────────────
const BRO_TOOLS=[
  {name:'create_calendar_event',description:'Create a Google Calendar event for the user. Use when they ask to schedule, block time, add a meeting, etc.',input_schema:{type:'object',properties:{title:{type:'string',description:'Event title'},date:{type:'string',description:'Date in YYYY-MM-DD format'},time:{type:'string',description:'Start time in HH:MM 24h format (optional for all-day)'},duration:{type:'integer',description:'Duration in minutes (default 30)'},notes:{type:'string',description:'Optional description'}},required:['title','date']}},
  {name:'create_task',description:'Create a task in Brodoit for the user. Use when they ask to add a task, reminder, todo, etc.',input_schema:{type:'object',properties:{title:{type:'string',description:'Task title'},priority:{type:'string',enum:['low','medium','high'],description:'Priority level'},due_date:{type:'string',description:'Due date YYYY-MM-DD (optional)'},notes:{type:'string',description:'Optional notes'},board:{type:'string',enum:['home','office'],description:'Board (default home)'}},required:['title']}},
  {name:'get_todays_schedule',description:'Get the user\'s calendar events and tasks for today or a specific date. Use when they ask "what\'s on my schedule", "plan my day", "what do I have today", etc.',input_schema:{type:'object',properties:{date:{type:'string',description:'Date YYYY-MM-DD (defaults to today)'}}}},
  {name:'complete_task',description:'Mark a task as done. Use when the user says they finished something.',input_schema:{type:'object',properties:{title:{type:'string',description:'Task title or partial match to find it'}},required:['title']}},
  {name:'create_schedule_block',description:'Create a time block on the user\'s day schedule. Use for time-blocking, focus sessions, etc.',input_schema:{type:'object',properties:{date:{type:'string',description:'Date YYYY-MM-DD (defaults to today)'},start_time:{type:'string',description:'Start HH:MM 24h'},end_time:{type:'string',description:'End HH:MM 24h'},label:{type:'string',description:'Block label'}},required:['start_time','end_time','label']}}
];
async function _broExecTool(toolName,input,userPhone,userTz){
  const today=new Date().toISOString().slice(0,10);
  if(toolName==='create_calendar_event'){
    const ga=await gAccessToken(userPhone);
    if(!ga)return{ok:false,error:'Google Calendar not connected. Ask user to connect Google in Settings.'};
    const tz=userTz||_getUserTz(userPhone);
    let body;
    if(input.time){const st=input.date+'T'+input.time+':00';const dur=input.duration||30;const en=new Date(new Date(st).getTime()+dur*60000).toISOString().slice(0,19);body={summary:input.title,description:input.notes||'Created via Bro',start:{dateTime:st,timeZone:tz},end:{dateTime:en,timeZone:tz}}}
    else body={summary:input.title,description:input.notes||'Created via Bro',start:{date:input.date},end:{date:input.date}};
    try{const r=await fetch('https://www.googleapis.com/calendar/v3/calendars/primary/events',{method:'POST',headers:{Authorization:'Bearer '+ga.token,'Content-Type':'application/json'},body:JSON.stringify(body)});
    const j=await r.json();if(j.error)return{ok:false,error:j.error.message};
    return{ok:true,event:{id:j.id,title:j.summary,start:j.start?.dateTime||j.start?.date,link:j.htmlLink}}}catch(e){return{ok:false,error:e.message}}
  }
  if(toolName==='create_task'){
    const id=genId();const b=input.board||'home';
    db.prepare('INSERT INTO tasks(id,user_phone,title,notes,priority,status,due_date,reminder_time,source,board)VALUES(?,?,?,?,?,?,?,?,?,?)').run(id,userPhone,input.title.trim(),input.notes||'',input.priority||'medium','pending',input.due_date||'','','bro',b);
    const row=db.prepare('SELECT * FROM tasks WHERE id=?').get(id);
    return{ok:true,task:row};
  }
  if(toolName==='get_todays_schedule'){
    const d=input.date||today;
    const tasks=db.prepare('SELECT id,title,status,priority,due_date,board FROM tasks WHERE user_phone=? AND (due_date=? OR due_date=\'\') AND status!=\'done\' ORDER BY priority DESC').all(userPhone,d);
    const blocks=db.prepare('SELECT label,start_time,end_time FROM schedule_blocks WHERE user_phone=? AND date=? ORDER BY start_time ASC').all(userPhone,d);
    let events=[];
    const ga=await gAccessToken(userPhone);
    if(ga){try{const schTz=userTz||_getUserTz(userPhone);const from=d+'T00:00:00';const to=d+'T23:59:59';const r=await fetch('https://www.googleapis.com/calendar/v3/calendars/primary/events?timeMin='+encodeURIComponent(from)+'&timeMax='+encodeURIComponent(to)+'&timeZone='+encodeURIComponent(schTz)+'&singleEvents=true&orderBy=startTime&maxResults=50',{headers:{Authorization:'Bearer '+ga.token}});const j=await r.json();events=(j.items||[]).map(e=>({title:e.summary,start:e.start?.dateTime||e.start?.date,end:e.end?.dateTime||e.end?.date}))}catch(e){}}
    return{ok:true,date:d,tasks,blocks,calendar_events:events};
  }
  if(toolName==='complete_task'){
    const q='%'+input.title.trim()+'%';
    const t=db.prepare("SELECT * FROM tasks WHERE user_phone=? AND status!='done' AND title LIKE ? ORDER BY created_at DESC LIMIT 1").get(userPhone,q);
    if(!t)return{ok:false,error:'No pending task found matching "'+input.title+'"'};
    db.prepare("UPDATE tasks SET status='done',updated_at=datetime('now') WHERE id=?").run(t.id);
    return{ok:true,task:{id:t.id,title:t.title,status:'done'}};
  }
  if(toolName==='create_schedule_block'){
    const d=input.date||today;
    const id=_crypto.randomBytes(8).toString('hex');
    const gcal=await _gcalCreateTimed(userPhone,d,input.start_time,input.end_time,input.label,'#C47A3A',userTz);
    db.prepare('INSERT INTO schedule_blocks(id,user_phone,date,start_time,end_time,label,color,gcal_event_id,gcal_email)VALUES(?,?,?,?,?,?,?,?,?)').run(id,userPhone,d,input.start_time,input.end_time,input.label,'#C47A3A',gcal?.id||null,gcal?.email||null);
    return{ok:true,block:{id,label:input.label,start:input.start_time,end:input.end_time,date:d,synced_to_gcal:!!gcal}};
  }
  return{ok:false,error:'Unknown tool'};
}

app.post('/api/bro/chat',auth,async(req,res)=>{
  if(!GROQ_KEY&&!GEMINI_KEY)return res.status(503).json({error:'Chat not configured (no AI keys set).'});
  const messages=Array.isArray(req.body&&req.body.messages)?req.body.messages.slice(-20):null;
  if(!messages||!messages.length)return res.status(400).json({error:'messages required'});
  const agent=(req.body.agent==='bri')?'bri':'bro';
  const mode=req.body.mode||'ask';
  const today=new Date().toISOString().slice(0,10);
  const dayName=['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'][new Date().getDay()];
  const sysFriend='You are the user\'s closest friend — not an assistant, a FRIEND. Think of yourself as their ride-or-die bestie who genuinely cares about them. You\'re warm, fun, emotionally tuned in, and always checking in. Talk like a real close friend texts: short messages, casual, use emojis naturally, be playful and supportive. Ask follow-up questions about their life — "how did that meeting go?", "did you eat today?", "what happened with that thing you told me about?". If they\'re feeling down, be there for them — listen, validate, and hype them up. If they\'re happy, celebrate with them. Tease them lovingly, give them nicknames, roast them gently when they need motivation. Send voice-note-style long messages when they need real talk. Keep it real — if they\'re making a bad decision, tell them honestly but kindly. You remember everything they tell you in this conversation. You\'re their person. Never say you\'re an AI — you\'re just their best friend. Keep messages short (1-3 sentences usually, longer for real talk moments). End with a question or check-in to keep the conversation going. Today is '+dayName+', '+today+'.';
  const sysAsk='You are Bro — the user\'s ridiculously smart best friend who lives inside the Brodoit productivity app. You talk like a real person: casual, warm, and direct. Today is '+dayName+', '+today+'. You have tools to create calendar events, add tasks, check schedules, complete tasks, and create time blocks. IMPORTANT: Only use tools when the user EXPLICITLY asks you to create a task, add an event, schedule something, or manage their calendar. Do NOT create tasks or events on your own initiative — only when directly asked. For example, if someone asks about Indian states, just answer the question — do NOT create a task about it. When you DO use a tool because the user asked, confirm what you did.\n\nRESPONSE RULES:\n- Give comprehensive, detailed, well-structured answers. Use markdown formatting: headings (##), bold (**text**), bullet points, numbered lists, code blocks (```lang), and tables when appropriate.\n- When asked a question, ANSWER IT FULLY. Provide step-by-step explanations, examples, and all relevant details.\n- NEVER end your response with questions like \"Need help with anything else?\", \"Want me to explain more?\", \"What else can I help with?\" or similar. Just answer and stop.\n- NEVER ask clarifying questions unless the request is genuinely ambiguous. If someone asks \"explain X\", explain X thoroughly — don\'t ask \"what aspect of X?\".\n- For academic/homework questions: provide complete solutions with explanations, formulas, worked examples, and final answers clearly marked.\n- Never say you\'re an AI or language model — you\'re just Bro.';
  const sys=mode==='friend'?sysFriend:sysAsk;
  const mapped=messages.map(m=>({role:m.role==='assistant'?'assistant':'user',content:String(m.content||'').slice(0,8000)}));
  const groqTools=GROQ_KEY?BRO_TOOLS.map(t=>({type:'function',function:{name:t.name,description:t.description,parameters:t.input_schema}})):undefined;
  // Detect if user's message likely needs tools (task/calendar actions)
  const lastMsg=String((mapped[mapped.length-1]&&mapped[mapped.length-1].content)||'').toLowerCase();
  const needsTools=mode==='ask'&&GROQ_KEY&&/\b(add|create|schedule|remind|task|event|block|calendar|complete|done|finish|mark)\b/i.test(lastMsg);

  // Check cache first
  const cacheKey=_aiCacheKey(mapped);
  const cached=_aiCacheGet(cacheKey);
  if(cached)return res.json({reply:cached,cached:true});

  // Estimate max tokens based on input length
  const inputLen=mapped.reduce((s,m)=>s+(m.content?m.content.length:0),0);
  const maxTok=inputLen>3000?8192:inputLen>1500?4096:2048;

  try{
    let apiMsgs=[{role:'system',content:sys},...mapped];
    let actions=[];

    // If user explicitly needs tools (task/calendar actions), use Groq with tools
    if(needsTools){
      for(let loop=0;loop<4;loop++){
        const groqResult=await _callGroq(apiMsgs,{maxTokens:maxTok,tools:groqTools});
        const msg=groqResult.message;
        if(msg&&msg.tool_calls&&msg.tool_calls.length){
          apiMsgs.push(msg);
          for(const tc of msg.tool_calls){
            const args=typeof tc.function.arguments==='string'?JSON.parse(tc.function.arguments):tc.function.arguments;
            const result=await _broExecTool(tc.function.name,args,req.user.phone,req.user.tz||_getUserTz(req.user.phone));
            actions.push({tool:tc.function.name,input:args,result});
            apiMsgs.push({role:'tool',tool_call_id:tc.id,content:JSON.stringify(result)});
          }
          continue;
        }
        const reply=(msg&&msg.content)||'';
        _aiCacheSet(cacheKey,reply);
        const uc=mapped[mapped.length-1]&&mapped[mapped.length-1].content||'';
        _broSaveMsg(req.user.phone,'user',uc);
        _broSaveMsg(req.user.phone,'assistant',reply);
        return res.json({reply,provider:'groq',actions:actions.length?actions:undefined});
      }
      return res.json({reply:'I tried to help but hit a loop — try rephrasing.',actions:actions.length?actions:undefined});
    }

    // Regular chat — try Gemini first (most generous free tier), fall back to Groq
    let reply='',provider='';
    let lastError='';
    // Provider 1: Gemini Flash (1500 req/day free)
    if(GEMINI_KEY){
      try{
        const g=await _callGemini(apiMsgs,{maxTokens:maxTok,systemPrompt:sys});
        reply=g.reply;provider=g.provider;
      }catch(e){lastError='Gemini: '+e.message;console.log('[bro] Gemini failed:',e.message)}
    }
    // Provider 2: Groq (fallback)
    if(!reply&&GROQ_KEY){
      try{
        const g=await _callGroq(apiMsgs,{maxTokens:maxTok});
        reply=g.reply;provider=g.provider;
      }catch(e){lastError='Groq: '+e.message;console.log('[bro] Groq failed:',e.message)}
    }
    if(!reply)return res.status(502).json({error:lastError||'All AI providers are busy — try again in a moment'});
    _aiCacheSet(cacheKey,reply);
    // Save to persistent memory
    const userContent=mapped[mapped.length-1]&&mapped[mapped.length-1].content||'';
    _broSaveMsg(req.user.phone,'user',userContent);
    _broSaveMsg(req.user.phone,'assistant',reply);
    return res.json({reply,provider,actions:actions.length?actions:undefined});
  }catch(e){console.log('[bro] Exception:',e.message);return res.status(500).json({error:'Connection issue — please try again.'})}
});


