// Used by <audio src> for affirmations + guided meditations (static MP3s).

app.get('/api/audio/:id', async (req, res) => {
  const token = String(req.query.token || req.headers['x-token'] || '').trim();
  const u = token ? db.prepare('SELECT * FROM users WHERE token=?').get(token) : null;
  if (!u) return res.status(401).json({ error: 'unauthorized' });
  const id = String(req.params.id || '').replace(/[^a-zA-Z0-9_-]/g, '');
  const entry = AUDIO_LIBRARY[id];
  if (!entry) return res.status(404).json({ error: 'unknown audio id' });

  // 1) Check for pre-baked static MP3 (bundled in repo — zero API cost)
  const staticPath = _path.join(__dirname, 'audio-static', id + '.mp3');
  try {
    if (_fs.existsSync(staticPath)) {
      const stat = _fs.statSync(staticPath);
      const total = stat.size;
      // Handle Range requests (required for iOS Safari audio playback)
      const range = req.headers.range;
      if (range) {
        const parts = range.replace(/bytes=/, '').split('-');
        const start = parseInt(parts[0], 10);
        const end = parts[1] ? parseInt(parts[1], 10) : total - 1;
        const chunkSize = end - start + 1;
        res.writeHead(206, {
          'Content-Range': 'bytes ' + start + '-' + end + '/' + total,
          'Accept-Ranges': 'bytes',
          'Content-Length': String(chunkSize),
          'Content-Type': 'audio/mpeg',
          'Cache-Control': 'public, max-age=604800',
          'X-Tts-Source': 'static',
        });
        return _fs.createReadStream(staticPath, { start, end }).pipe(res);
      }
      res.set('Content-Type', 'audio/mpeg');
      res.set('Cache-Control', 'public, max-age=604800');
      res.set('X-Tts-Source', 'static');
      res.set('Content-Length', String(total));
      res.set('Accept-Ranges', 'bytes');
      return _fs.createReadStream(staticPath).pipe(res);
    }
  } catch (e) {}

  // No static file — tell client to use browser TTS fallback
  return res.status(404).json({ error: 'audio not found — use browser TTS' });
});

// GET /api/audio-library — small JSON manifest the client uses to render cards.
