// Google Fit step sync — reads hardware step data from phone sensors
app.post('/api/steps/sync-fit',auth,async(req,res)=>{
  try{
    const ga=await gAccessToken(req.user.phone);
    if(!ga)return res.status(401).json({error:'Google account not connected. Connect Google in Calendar tab first.'});
    const days=Math.min(Math.max(parseInt(req.body.days)||7,1),30);
    const endMs=Date.now();
    const startMs=endMs-days*864e5;
    const fitRes=await fetch('https://www.googleapis.com/fitness/v1/users/me/dataset:aggregate',{
      method:'POST',
      headers:{Authorization:'Bearer '+ga.token,'Content-Type':'application/json'},
      body:JSON.stringify({
        aggregateBy:[{dataTypeName:'com.google.step_count.delta',dataSourceId:'derived:com.google.step_count.delta:com.google.android.gms:estimated_steps'}],
        bucketByTime:{durationMillis:86400000},
        startTimeMillis:startMs,
        endTimeMillis:endMs
      })
    });
    if(!fitRes.ok){
      const errBody=await fitRes.text();
      if(fitRes.status===403||fitRes.status===401)return res.status(403).json({error:'Fitness permission not granted. Please reconnect Google account to allow step tracking.',needReauth:true});
      return res.status(fitRes.status).json({error:'Google Fit error: '+fitRes.status});
    }
    const fitData=await fitRes.json();
    const synced=[];
    for(const bucket of(fitData.bucket||[])){
      const d=new Date(parseInt(bucket.startTimeMillis)).toISOString().slice(0,10);
      let steps=0;
      for(const ds of(bucket.dataset||[])){for(const pt of(ds.point||[])){for(const v of(pt.value||[])){steps+=(v.intVal||0)}}}
      if(steps>0){
        const existing=db.prepare('SELECT count,source FROM steps WHERE user_phone=? AND date=?').get(req.user.phone,d);
        if(!existing||existing.source==='googlefit'||steps>existing.count){
          db.prepare("INSERT INTO steps(user_phone,date,count,source,updated_at)VALUES(?,?,?,'googlefit',datetime('now'))ON CONFLICT(user_phone,date)DO UPDATE SET count=excluded.count,source='googlefit',updated_at=datetime('now')").run(req.user.phone,d,steps);
          synced.push({date:d,count:steps});
        }
      }
    }
    res.json({ok:true,synced,days});
  }catch(e){res.status(500).json({error:'Sync failed: '+e.message})}
});
// ═══ BOOK LISTENING STREAK ═══
function calcStreak(rows){
  // rows: [{date}] sorted DESC
  if(!rows.length)return 0;
  const today=new Date().toISOString().slice(0,10);
  const yest=new Date(Date.now()-864e5).toISOString().slice(0,10);
  // Streak only continues if last listen was today or yesterday
  if(rows[0].date!==today&&rows[0].date!==yest)return 0;
  let streak=0;
  let cur=new Date(rows[0].date);
  for(const r of rows){
    const expected=cur.toISOString().slice(0,10);
    if(r.date===expected){streak++;cur.setDate(cur.getDate()-1)}
    else if(r.date<expected)break;
  }
  return streak;
}
app.get('/api/book-streak',auth,(req,res)=>{
  const rows=db.prepare('SELECT date FROM book_listens WHERE user_phone=? ORDER BY date DESC LIMIT 365').all(req.user.phone);
  const today=new Date().toISOString().slice(0,10);
  res.json({streak:calcStreak(rows),total:rows.length,today:rows.some(r=>r.date===today),days:rows.slice(0,30).map(r=>r.date)});
});
app.post('/api/book-streak',auth,(req,res)=>{
  const d=String(req.body?.date||new Date().toISOString().slice(0,10)).slice(0,10);
  const sec=Math.min(Math.max(parseInt(req.body?.seconds)||120,60),24*3600);
  // Insert if missing; otherwise sum the seconds (cap at 24h)
  const ex=db.prepare('SELECT seconds FROM book_listens WHERE user_phone=? AND date=?').get(req.user.phone,d);
  if(ex){db.prepare('UPDATE book_listens SET seconds=MIN(seconds+?,86400) WHERE user_phone=? AND date=?').run(sec,req.user.phone,d)}
  else{db.prepare('INSERT INTO book_listens(user_phone,date,seconds)VALUES(?,?,?)').run(req.user.phone,d,sec)}
  const rows=db.prepare('SELECT date FROM book_listens WHERE user_phone=? ORDER BY date DESC LIMIT 365').all(req.user.phone);
  res.json({ok:true,streak:calcStreak(rows),total:rows.length});
});

// ═══ GOOGLE CALENDAR INTEGRATION (OAuth 2.0) ═══
const G_CLIENT_ID=process.env.GOOGLE_CLIENT_ID||'';
const G_CLIENT_SECRET=process.env.GOOGLE_CLIENT_SECRET||'';
const G_REDIRECT=process.env.GOOGLE_REDIRECT_URI||(process.env.PUBLIC_URL?process.env.PUBLIC_URL.replace(/\/$/,'')+'/api/google/callback':'https://brodoit.com/api/google/callback');
const G_SCOPES=['https://www.googleapis.com/auth/calendar','https://www.googleapis.com/auth/userinfo.email','https://www.googleapis.com/auth/fitness.activity.read','openid'].join(' ');
const googleConfigured=()=>!!(G_CLIENT_ID&&G_CLIENT_SECRET);
app.get('/api/google/status',auth,(req,res)=>{
  const accounts=db.prepare('SELECT email,is_default,created_at FROM google_tokens WHERE user_phone=? ORDER BY is_default DESC,created_at ASC').all(req.user.phone);
  res.json({configured:googleConfigured(),accounts,redirectUri:G_REDIRECT});
});
app.get('/api/google/auth-url',auth,(req,res)=>{
  if(!googleConfigured())return res.status(503).json({error:'Google integration not configured. Admin must set GOOGLE_CLIENT_ID and GOOGLE_CLIENT_SECRET.'});
  const state=crypto.randomBytes(24).toString('hex');
  db.prepare('INSERT INTO oauth_states(state,user_phone,created_at)VALUES(?,?,?)').run(state,req.user.phone,Date.now());
  // expire old states (>10 min)
  db.prepare('DELETE FROM oauth_states WHERE created_at<?').run(Date.now()-10*60*1000);
  const params=new URLSearchParams({client_id:G_CLIENT_ID,redirect_uri:G_REDIRECT,response_type:'code',scope:G_SCOPES,access_type:'offline',prompt:'consent select_account',state,include_granted_scopes:'true'});
  res.json({url:'https://accounts.google.com/o/oauth2/v2/auth?'+params.toString()});
});
app.get('/api/google/callback',async(req,res)=>{
  const{code,state,error:authErr}=req.query;
  if(authErr)return res.send('<html><body style="font-family:system-ui;padding:40px;text-align:center"><h2>Connection cancelled</h2><p>'+String(authErr).replace(/[<>]/g,'')+'</p><a href="/">Back to Brodoit</a></body></html>');
  if(!code||!state)return res.status(400).send('Missing code or state');
  const row=db.prepare('SELECT user_phone FROM oauth_states WHERE state=?').get(state);
  if(!row)return res.status(400).send('Invalid or expired state');
  db.prepare('DELETE FROM oauth_states WHERE state=?').run(state);
  try{
    const tokenResp=await fetch('https://oauth2.googleapis.com/token',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:new URLSearchParams({code,client_id:G_CLIENT_ID,client_secret:G_CLIENT_SECRET,redirect_uri:G_REDIRECT,grant_type:'authorization_code'}).toString()});
    const tj=await tokenResp.json();
    if(!tj.access_token)return res.status(400).send('<html><body style="font-family:system-ui;padding:40px;text-align:center"><h2>Token exchange failed</h2><pre>'+JSON.stringify(tj).replace(/[<>]/g,'')+'</pre></body></html>');
    const ui=await fetch('https://openidconnect.googleapis.com/v1/userinfo',{headers:{Authorization:'Bearer '+tj.access_token}}).then(r=>r.json()).catch(()=>({}));
    const email=(ui.email||'').toLowerCase();
    if(!email)return res.status(400).send('Could not read your Google email.');
    const expires_at=Date.now()+(tj.expires_in||3600)*1000;
    const existing=db.prepare('SELECT email FROM google_tokens WHERE user_phone=?').all(row.user_phone);
    const isFirst=existing.length===0?1:0;
    db.prepare("INSERT INTO google_tokens(user_phone,email,access_token,refresh_token,expires_at,scope,is_default)VALUES(?,?,?,?,?,?,?)ON CONFLICT(user_phone,email) DO UPDATE SET access_token=excluded.access_token,refresh_token=COALESCE(excluded.refresh_token,google_tokens.refresh_token),expires_at=excluded.expires_at,scope=excluded.scope").run(row.user_phone,email,tj.access_token,tj.refresh_token||null,expires_at,tj.scope||'',isFirst);
    res.send('<html><head><title>Brodoit \\u2014 Google connected</title></head><body style="font-family:system-ui;padding:40px;text-align:center;background:linear-gradient(135deg,#FFF8F0,#FFF);min-height:100vh;display:flex;align-items:center;justify-content:center"><div><div style="font-size:72px">\\u2705</div><h2 style="margin:8px 0;font-size:26px">Google Calendar connected</h2><p style="color:#9C8B7A;font-size:15px;margin-bottom:24px"><b>'+email.replace(/[<>]/g,'')+'</b> is now linked. Closing this tab\\u2026</p><a href="/" style="display:inline-block;padding:12px 24px;background:#3A2D22;color:#fff;border-radius:10px;text-decoration:none;font-weight:600">Open Brodoit</a><script>setTimeout(()=>{try{if(window.opener){window.opener.postMessage({type:"google-connected",email:"'+email.replace(/[^a-z0-9@._-]/gi,'')+'"},"*");window.close()}else{location.href="/?google=connected"}}catch(e){location.href="/?google=connected"}},1500);<\\/script></div></body></html>');
  }catch(e){res.status(500).send('Auth error: '+String(e.message).replace(/[<>]/g,''))}
});
async function gAccessToken(user_phone,email){
  const row=email?db.prepare('SELECT * FROM google_tokens WHERE user_phone=? AND email=?').get(user_phone,email):db.prepare('SELECT * FROM google_tokens WHERE user_phone=? ORDER BY is_default DESC LIMIT 1').get(user_phone);
  if(!row)return null;
  if(Date.now()<row.expires_at-30000)return{token:row.access_token,email:row.email};
  if(!row.refresh_token)return null;
  try{
    const r=await fetch('https://oauth2.googleapis.com/token',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:new URLSearchParams({client_id:G_CLIENT_ID,client_secret:G_CLIENT_SECRET,refresh_token:row.refresh_token,grant_type:'refresh_token'}).toString()});
    const j=await r.json();
    if(!j.access_token)return null;
    const expires_at=Date.now()+(j.expires_in||3600)*1000;
    db.prepare('UPDATE google_tokens SET access_token=?,expires_at=? WHERE user_phone=? AND email=?').run(j.access_token,expires_at,user_phone,row.email);
    return{token:j.access_token,email:row.email};
  }catch(e){return null}
}
app.post('/api/google/disconnect',auth,(req,res)=>{
  const email=(req.body.email||'').toLowerCase();
  if(email)db.prepare('DELETE FROM google_tokens WHERE user_phone=? AND email=?').run(req.user.phone,email);
  else db.prepare('DELETE FROM google_tokens WHERE user_phone=?').run(req.user.phone);
  res.json({ok:true});
});
app.post('/api/google/set-default',auth,(req,res)=>{
  const email=(req.body.email||'').toLowerCase();if(!email)return res.status(400).json({error:'email required'});
  const exists=db.prepare('SELECT 1 FROM google_tokens WHERE user_phone=? AND email=?').get(req.user.phone,email);
  if(!exists)return res.status(404).json({error:'not connected'});
  db.prepare('UPDATE google_tokens SET is_default=0 WHERE user_phone=?').run(req.user.phone);
  db.prepare('UPDATE google_tokens SET is_default=1 WHERE user_phone=? AND email=?').run(req.user.phone,email);
  res.json({ok:true});
});
app.get('/api/calendar/events',auth,async(req,res)=>{
  const email=req.query.email;const ga=await gAccessToken(req.user.phone,email);
  if(!ga)return res.status(400).json({error:'Google Calendar not connected'});
  const now=new Date();const from=req.query.from||new Date(now.getFullYear(),now.getMonth()-1,1).toISOString();const to=req.query.to||new Date(now.getFullYear(),now.getMonth()+2,0).toISOString();
  const calTz=_getUserTz(req.user.phone);
  const url='https://www.googleapis.com/calendar/v3/calendars/primary/events?timeMin='+encodeURIComponent(from)+'&timeMax='+encodeURIComponent(to)+'&timeZone='+encodeURIComponent(calTz)+'&singleEvents=true&orderBy=startTime&maxResults=100';
  try{
    const r=await fetch(url,{headers:{Authorization:'Bearer '+ga.token}});
    const j=await r.json();
    if(j.error){if(j.error.status==='PERMISSION_DENIED'||/insufficient.*scope/i.test(j.error.message||''))return res.status(403).json({error:'Calendar permissions need updating. Disconnect and reconnect your Google account.'});return res.status(400).json({error:j.error.message||'fetch failed'})}
    const items=(j.items||[]).map(e=>({id:e.id,title:e.summary||'(no title)',start:e.start?.dateTime||e.start?.date||'',end:e.end?.dateTime||e.end?.date||'',allDay:!!(e.start&&e.start.date&&!e.start.dateTime),link:e.htmlLink,location:e.location||''}));
    res.json({email:ga.email,events:items});
  }catch(e){res.status(500).json({error:e.message})}
});
app.post('/api/calendar/events',auth,async(req,res)=>{
  const{title,date,time,duration,notes,email,tz:bodyTz}=req.body;
  if(!title||!date)return res.status(400).json({error:'title and date required'});
  const ga=await gAccessToken(req.user.phone,email);if(!ga)return res.status(400).json({error:'Google Calendar not connected'});
  const tz=bodyTz||_getUserTz(req.user.phone);
  let body;
  if(time){const startISO=date+'T'+time+':00';const endTime=new Date(new Date(startISO).getTime()+(duration||30)*60000).toISOString().slice(0,19);body={summary:title,description:notes||'Created via Brodoit',start:{dateTime:startISO,timeZone:tz},end:{dateTime:endTime,timeZone:tz}}}
  else body={summary:title,description:notes||'Created via Brodoit',start:{date},end:{date}};
  try{
    const r=await fetch('https://www.googleapis.com/calendar/v3/calendars/primary/events',{method:'POST',headers:{Authorization:'Bearer '+ga.token,'Content-Type':'application/json'},body:JSON.stringify(body)});
    const j=await r.json();
    if(j.error)return res.status(400).json({error:j.error.message});
    res.json({ok:true,event:{id:j.id,title:j.summary,link:j.htmlLink,start:j.start?.dateTime||j.start?.date}});
  }catch(e){res.status(500).json({error:e.message})}
});
app.delete('/api/calendar/events/:id',auth,async(req,res)=>{
  const ga=await gAccessToken(req.user.phone,req.query.email);if(!ga)return res.status(400).json({error:'not connected'});
  try{
    const r=await fetch('https://www.googleapis.com/calendar/v3/calendars/primary/events/'+encodeURIComponent(req.params.id),{method:'DELETE',headers:{Authorization:'Bearer '+ga.token}});
    if(r.status===204||r.ok)return res.json({ok:true});
    const j=await r.json().catch(()=>({}));
    res.status(400).json({error:j.error?.message||'delete failed'});
  }catch(e){res.status(500).json({error:e.message})}
});
// ─── Daily Highlight API ─────────────────────────────────────────────
function _todayISO(){return new Date().toISOString().slice(0,10)}
async function _gcalCreateAllDay(userPhone,date,text){
  const def=db.prepare("SELECT email FROM google_tokens WHERE user_phone=? ORDER BY is_default DESC LIMIT 1").get(userPhone);
  if(!def)return null;
  const ga=await gAccessToken(userPhone,def.email);if(!ga)return null;
  const next=new Date(date+'T00:00:00Z');next.setUTCDate(next.getUTCDate()+1);
  const body={summary:'\u{1F31F} Today’s Highlight: '+text,description:'Your daily highlight from Brodoit. Tap and complete this one thing today.',start:{date},end:{date:next.toISOString().slice(0,10)},colorId:'5'};
  try{
    const r=await fetch('https://www.googleapis.com/calendar/v3/calendars/primary/events',{method:'POST',headers:{Authorization:'Bearer '+ga.token,'Content-Type':'application/json'},body:JSON.stringify(body)});
    const j=await r.json();if(j.error)return null;
    return {id:j.id,email:def.email,link:j.htmlLink};
  }catch(e){return null}
}
async function _gcalDeleteEvent(userPhone,email,eventId){
  if(!eventId||!email)return;
  const ga=await gAccessToken(userPhone,email);if(!ga)return;
  try{await fetch('https://www.googleapis.com/calendar/v3/calendars/primary/events/'+encodeURIComponent(eventId),{method:'DELETE',headers:{Authorization:'Bearer '+ga.token}})}catch(e){}
}
app.get('/api/highlight',auth,(req,res)=>{
  const row=db.prepare('SELECT * FROM daily_highlights WHERE user_phone=? AND date=?').get(req.user.phone,_todayISO());
  res.json({highlight:row||null});
});
app.post('/api/highlight',auth,async(req,res)=>{
  const text=String((req.body&&req.body.text)||'').trim().slice(0,200);
  if(!text)return res.status(400).json({error:'text required'});
  const today=_todayISO();
  const existing=db.prepare('SELECT * FROM daily_highlights WHERE user_phone=? AND date=?').get(req.user.phone,today);
  if(existing){
    // Edit existing — update text, push update to GCal if event still attached
    db.prepare("UPDATE daily_highlights SET text=?,updated_at=datetime('now') WHERE user_phone=? AND date=?").run(text,req.user.phone,today);
    if(existing.gcal_event_id&&existing.gcal_email){
      try{
        const ga=await gAccessToken(req.user.phone,existing.gcal_email);
        if(ga){await fetch('https://www.googleapis.com/calendar/v3/calendars/primary/events/'+encodeURIComponent(existing.gcal_event_id),{method:'PATCH',headers:{Authorization:'Bearer '+ga.token,'Content-Type':'application/json'},body:JSON.stringify({summary:'\u{1F31F} Today’s Highlight: '+text})})}
      }catch(e){}
    }
    return res.json({ok:true,highlight:{...existing,text}});
  }
  // New highlight — create + push to GCal if connected
  const gcal=await _gcalCreateAllDay(req.user.phone,today,text);
  db.prepare('INSERT INTO daily_highlights(user_phone,date,text,gcal_event_id,gcal_email)VALUES(?,?,?,?,?)').run(req.user.phone,today,text,gcal?.id||null,gcal?.email||null);
  const row=db.prepare('SELECT * FROM daily_highlights WHERE user_phone=? AND date=?').get(req.user.phone,today);
  // Send the morning email immediately as a confirmation that it was saved + scheduled
  try{
    const u=db.prepare('SELECT email,name FROM users WHERE phone=?').get(req.user.phone);
    if(u&&u.email&&isEmail(u.email)){
      const firstName=(u.name||'').split(' ')[0]||'there';
      const html=_hlEmailHTML(firstName,text,gcal?.link);
      await sendEmail(u.email,'\u{1F31F} '+text+' — today’s highlight',html);
      db.prepare('UPDATE daily_highlights SET reminded_morning=1 WHERE user_phone=? AND date=?').run(req.user.phone,today);
    }
  }catch(e){}
  res.json({ok:true,highlight:row,gcal:gcal||null});
});
app.post('/api/highlight/done',auth,(req,res)=>{
  const done=req.body&&req.body.done?1:0;
  db.prepare("UPDATE daily_highlights SET done=?,updated_at=datetime('now') WHERE user_phone=? AND date=?").run(done,req.user.phone,_todayISO());
  res.json({ok:true});
});
app.delete('/api/highlight',auth,async(req,res)=>{
  const today=_todayISO();
  const existing=db.prepare('SELECT * FROM daily_highlights WHERE user_phone=? AND date=?').get(req.user.phone,today);
  if(existing&&existing.gcal_event_id&&existing.gcal_email){await _gcalDeleteEvent(req.user.phone,existing.gcal_email,existing.gcal_event_id)}
  db.prepare('DELETE FROM daily_highlights WHERE user_phone=? AND date=?').run(req.user.phone,today);
  res.json({ok:true});
});
// Email template for highlight reminders
function _hlEmailHTML(name,text,gcalLink){
  return '<!doctype html><html><body style="font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Helvetica,Arial,sans-serif;background:#FBF7F1;margin:0;padding:32px 16px"><table role="presentation" style="max-width:520px;margin:0 auto;background:#fff;border-radius:18px;overflow:hidden;box-shadow:0 8px 24px rgba(58,45,34,.08)"><tr><td style="background:linear-gradient(135deg,#D4956A 0%,#F0DFC8 100%);padding:28px 28px 24px;color:#fff"><div style="font-family:JetBrains Mono,monospace;font-size:11px;letter-spacing:.16em;text-transform:uppercase;opacity:.85;font-weight:600">Today’s Highlight</div><div style="font-family:Instrument Serif,Georgia,serif;font-style:italic;font-size:30px;line-height:1.15;margin-top:10px;color:#fff;letter-spacing:-.018em">'+esc(text)+'</div></td></tr><tr><td style="padding:24px 28px 28px;color:#3D3D3D;font-size:15px;line-height:1.6"><p style="margin:0 0 14px">Hi '+esc(name)+', this is the one thing you said would make today feel like a win.</p><p style="margin:0 0 18px">Block 60–90 minutes for it. Phone in another room. Door closed if you have one. Then ship it before lunch.</p><div style="margin:18px 0"><a href="https://brodoit.com" style="display:inline-block;padding:12px 22px;background:#3A2D22;color:#fff;text-decoration:none;border-radius:12px;font-weight:600;font-size:14px;letter-spacing:-.005em">Open Brodoit →</a>'+(gcalLink?'&nbsp;<a href="'+esc(gcalLink)+'" style="display:inline-block;padding:12px 22px;background:#fff;color:#3A2D22;text-decoration:none;border:1px solid #E8E6E0;border-radius:12px;font-weight:600;font-size:14px;letter-spacing:-.005em">View on Calendar</a>':'')+'</div><p style="margin:18px 0 0;font-size:13px;color:#6B6B6B">You can change tomorrow’s highlight anytime in the Tasks tab.</p></td></tr></table><div style="text-align:center;color:#9A9A9A;font-size:12px;margin-top:20px;font-family:JetBrains Mono,monospace;letter-spacing:.08em">BRODOIT • ONE THING TODAY</div></body></html>';
}
function _hlNudgeHTML(name,text,slot){
  const hook=slot==='midday'?'Halfway through the day. Did you start it yet?':'Last call before tonight. Don’t leave it for tomorrow-you to clean up.';
  return '<!doctype html><html><body style="font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Helvetica,Arial,sans-serif;background:#FBF7F1;margin:0;padding:32px 16px"><table role="presentation" style="max-width:520px;margin:0 auto;background:#fff;border-radius:18px;overflow:hidden;box-shadow:0 8px 24px rgba(58,45,34,.08)"><tr><td style="padding:28px 28px 18px"><div style="font-family:JetBrains Mono,monospace;font-size:11px;letter-spacing:.16em;text-transform:uppercase;color:#B7472A;font-weight:600">'+(slot==='midday'?'⏱ Midday Check-in':'\u{1F319} Evening Nudge')+'</div><div style="font-family:Instrument Serif,Georgia,serif;font-style:italic;font-size:24px;line-height:1.2;margin-top:10px;color:#3A2D22;letter-spacing:-.018em">'+esc(text)+'</div></td></tr><tr><td style="padding:8px 28px 26px;color:#3D3D3D;font-size:14.5px;line-height:1.6"><p style="margin:0 0 14px">Hi '+esc(name)+'. '+hook+'</p><div style="margin:14px 0"><a href="https://brodoit.com" style="display:inline-block;padding:11px 20px;background:linear-gradient(135deg,#D4956A,#F0DFC8);color:#fff;text-decoration:none;border-radius:12px;font-weight:600;font-size:14px">Mark it done →</a></div></td></tr></table></body></html>';
}
// Reminder loop — runs every 10 minutes, sends slot-specific emails to users
// who set a highlight today and haven't completed it.
async function _hlReminderTick(){
  try{
    const now=new Date();
    const hour=now.getHours();
    const today=_todayISO();
    let slot=null;
    if(hour>=12&&hour<=13)slot='midday';
    else if(hour>=18&&hour<=19)slot='evening';
    if(!slot)return;
    const col='reminded_'+slot;
    const rows=db.prepare("SELECT h.*,u.email,u.name FROM daily_highlights h JOIN users u ON u.phone=h.user_phone WHERE h.date=? AND h.done=0 AND h."+col+"=0").all(today);
    for(const r of rows){
      if(!r.email||!isEmail(r.email))continue;
      const firstName=(r.name||'').split(' ')[0]||'there';
      const html=_hlNudgeHTML(firstName,r.text,slot);
      const subject=slot==='midday'?'⏱ Midday — your highlight':'\u{1F319} Tonight — don’t forget your highlight';
      await sendEmail(r.email,subject,html);
      db.prepare('UPDATE daily_highlights SET '+col+'=1 WHERE user_phone=? AND date=?').run(r.user_phone,today);
    }
  }catch(e){console.warn('[hl-reminders]',e.message)}
}
setInterval(_hlReminderTick,10*60*1000);
setTimeout(_hlReminderTick,30*1000); // first check 30s after boot

// ─── Schedule Blocks API ──────────────────────────────────────────────
async function _gcalCreateTimed(userPhone,date,startTime,endTime,label,color,userTz){
  const def=db.prepare("SELECT email FROM google_tokens WHERE user_phone=? ORDER BY is_default DESC LIMIT 1").get(userPhone);
  if(!def)return null;
  const ga=await gAccessToken(userPhone,def.email);if(!ga)return null;
  const tz=userTz||_getUserTz(userPhone);
  const startISO=date+'T'+startTime+':00';
  const endISO=date+'T'+endTime+':00';
  const body={summary:'\u{1F512} '+label,description:'Time block from Brodoit. Phone away. Door closed.',start:{dateTime:startISO,timeZone:tz},end:{dateTime:endISO,timeZone:tz},colorId:color||'9'};
  try{
    const r=await fetch('https://www.googleapis.com/calendar/v3/calendars/primary/events',{method:'POST',headers:{Authorization:'Bearer '+ga.token,'Content-Type':'application/json'},body:JSON.stringify(body)});
    const j=await r.json();if(j.error)return null;
    return {id:j.id,email:def.email,link:j.htmlLink};
  }catch(e){return null}
}
app.get('/api/schedule',auth,(req,res)=>{
  const date=String(req.query.date||_todayISO());
  const rows=db.prepare('SELECT * FROM schedule_blocks WHERE user_phone=? AND date=? ORDER BY start_time ASC').all(req.user.phone,date);
  res.json({date,blocks:rows});
});
app.post('/api/schedule',auth,async(req,res)=>{
  const{date,start_time,end_time,label,color,tz:bodyTz}=req.body||{};
  const d=String(date||_todayISO());
  const st=String(start_time||'').match(/^(\d{2}):(\d{2})$/)?start_time:null;
  const et=String(end_time||'').match(/^(\d{2}):(\d{2})$/)?end_time:null;
  const lab=String(label||'').trim().slice(0,100);
  if(!st||!et||!lab)return res.status(400).json({error:'date, start_time HH:MM, end_time HH:MM, label required'});
  if(et<=st)return res.status(400).json({error:'end_time must be after start_time'});
  const id=_crypto.randomBytes(8).toString('hex');
  const userTz=bodyTz||_getUserTz(req.user.phone);
  const gcal=await _gcalCreateTimed(req.user.phone,d,st,et,lab,color||'',userTz);
  db.prepare('INSERT INTO schedule_blocks(id,user_phone,date,start_time,end_time,label,color,gcal_event_id,gcal_email)VALUES(?,?,?,?,?,?,?,?,?)').run(id,req.user.phone,d,st,et,lab,color||'',gcal?.id||null,gcal?.email||null);
  const row=db.prepare('SELECT * FROM schedule_blocks WHERE id=?').get(id);
  res.json({ok:true,block:row,gcal:gcal||null});
});
app.delete('/api/schedule/:id',auth,async(req,res)=>{
  const row=db.prepare('SELECT * FROM schedule_blocks WHERE id=? AND user_phone=?').get(req.params.id,req.user.phone);
  if(!row)return res.status(404).json({error:'not found'});
  if(row.gcal_event_id&&row.gcal_email){await _gcalDeleteEvent(req.user.phone,row.gcal_email,row.gcal_event_id)}
  db.prepare('DELETE FROM schedule_blocks WHERE id=?').run(req.params.id);
  res.json({ok:true});
});
// Reminder for blocks — fires once per block ~10 minutes before start
function _blockEmailHTML(name,label,startTime,endTime,gcalLink){
  return '<!doctype html><html><body style="font-family:-apple-system,BlinkMacSystemFont,Segoe UI,Helvetica,Arial,sans-serif;background:#FBF7F1;margin:0;padding:32px 16px"><table role="presentation" style="max-width:520px;margin:0 auto;background:#fff;border-radius:18px;overflow:hidden;box-shadow:0 8px 24px rgba(58,45,34,.08)"><tr><td style="background:linear-gradient(135deg,#5A3D22 0%,#7A5D3A 100%);padding:28px 28px 22px;color:#fff"><div style="font-family:JetBrains Mono,monospace;font-size:11px;letter-spacing:.16em;text-transform:uppercase;opacity:.78;font-weight:600">⏱ Time block in 10 min</div><div style="font-family:Instrument Serif,Georgia,serif;font-style:italic;font-size:30px;line-height:1.15;margin-top:10px;color:#fff;letter-spacing:-.018em">'+esc(label)+'</div><div style="margin-top:8px;font-family:Inter,sans-serif;font-size:14px;color:rgba(255,255,255,.85)">'+esc(startTime)+' → '+esc(endTime)+'</div></td></tr><tr><td style="padding:24px 28px 28px;color:#3D3D3D;font-size:15px;line-height:1.6"><p style="margin:0 0 14px">Hi '+esc(name)+', heads up — your scheduled block starts in about ten minutes.</p><p style="margin:0 0 18px">Phone away. Door closed if you have one. Make this time count.</p><div style="margin:18px 0"><a href="https://brodoit.com" style="display:inline-block;padding:12px 22px;background:#3A2D22;color:#fff;text-decoration:none;border-radius:12px;font-weight:600;font-size:14px;letter-spacing:-.005em">Open Brodoit →</a>'+(gcalLink?'&nbsp;<a href="'+esc(gcalLink)+'" style="display:inline-block;padding:12px 22px;background:#fff;color:#3A2D22;text-decoration:none;border:1px solid #E8E6E0;border-radius:12px;font-weight:600;font-size:14px;letter-spacing:-.005em">View on Calendar</a>':'')+'</div></td></tr></table><div style="text-align:center;color:#9A9A9A;font-size:12px;margin-top:20px;font-family:JetBrains Mono,monospace;letter-spacing:.08em">BRODOIT • TIME BLOCKING</div></body></html>';
}
async function _blockReminderTick(){
  try{
    const now=new Date();
    const today=_todayISO();
    // Find blocks starting in the next 10-20 minutes that haven't been reminded
    const rows=db.prepare("SELECT b.*,u.email,u.name FROM schedule_blocks b JOIN users u ON u.phone=b.user_phone WHERE b.date=? AND b.reminded=0").all(today);
    for(const r of rows){
      const [hh,mm]=r.start_time.split(':').map(Number);
      const start=new Date();start.setHours(hh,mm,0,0);
      const diffMin=(start.getTime()-now.getTime())/60000;
      if(diffMin>0&&diffMin<=12){
        if(!r.email||!isEmail(r.email)){db.prepare('UPDATE schedule_blocks SET reminded=1 WHERE id=?').run(r.id);continue}
        const firstName=(r.name||'').split(' ')[0]||'there';
        const html=_blockEmailHTML(firstName,r.label,r.start_time,r.end_time,null);
        await sendEmail(r.email,'⏱ '+r.label+' — starts in 10 min',html);
        db.prepare('UPDATE schedule_blocks SET reminded=1 WHERE id=?').run(r.id);
      }
    }
  }catch(e){console.warn('[block-reminders]',e.message)}
}
setInterval(_blockReminderTick,2*60*1000);
setTimeout(_blockReminderTick,15*1000);

// ─── Meeting Notes API ────────────────────────────────────────────────
const MEET_VOICE_DIR=process.env.MEET_VOICE_DIR||_path.join(process.cwd(),'meeting-voices');
try{_fs.mkdirSync(MEET_VOICE_DIR,{recursive:true})}catch(e){}
app.get('/api/meetings',auth,(req,res)=>{
  const rows=db.prepare('SELECT m.*,(SELECT COUNT(*) FROM meeting_voices v WHERE v.meeting_id=m.id) as voice_count FROM meetings m WHERE m.user_phone=? ORDER BY m.updated_at DESC LIMIT 200').all(req.user.phone);
  res.json({meetings:rows});
});
app.post('/api/meetings',auth,(req,res)=>{
  const id=_crypto.randomBytes(8).toString('hex');
  const title=String((req.body&&req.body.title)||'').trim().slice(0,200)||'Untitled meeting';
  const agenda=String((req.body&&req.body.agenda)||'').slice(0,4000);
  const notes=String((req.body&&req.body.notes)||'').slice(0,10000);
  db.prepare('INSERT INTO meetings(id,user_phone,title,agenda,notes)VALUES(?,?,?,?,?)').run(id,req.user.phone,title,agenda,notes);
  const row=db.prepare('SELECT m.*,0 as voice_count FROM meetings m WHERE m.id=?').get(id);
  res.json({ok:true,meeting:row});
});
app.get('/api/meetings/:id',auth,(req,res)=>{
  const m=db.prepare('SELECT * FROM meetings WHERE id=? AND user_phone=?').get(req.params.id,req.user.phone);
  if(!m)return res.status(404).json({error:'not found'});
  const voices=db.prepare('SELECT id,duration_sec,size_bytes,mime,created_at FROM meeting_voices WHERE meeting_id=? ORDER BY created_at ASC').all(m.id);
  res.json({meeting:m,voices});
});
app.put('/api/meetings/:id',auth,(req,res)=>{
  const m=db.prepare('SELECT id FROM meetings WHERE id=? AND user_phone=?').get(req.params.id,req.user.phone);
  if(!m)return res.status(404).json({error:'not found'});
  const fields=[],vals=[];
  ['title','agenda','notes'].forEach(k=>{if(req.body&&typeof req.body[k]==='string'){fields.push(k+'=?');vals.push(req.body[k].slice(0,k==='notes'?10000:k==='agenda'?4000:200))}});
  if(!fields.length)return res.json({ok:true});
  vals.push(req.params.id);
  db.prepare('UPDATE meetings SET '+fields.join(',')+",updated_at=datetime('now') WHERE id=?").run(...vals);
  res.json({ok:true});
});
app.delete('/api/meetings/:id',auth,(req,res)=>{
  const m=db.prepare('SELECT id FROM meetings WHERE id=? AND user_phone=?').get(req.params.id,req.user.phone);
  if(!m)return res.status(404).json({error:'not found'});
  // Delete voice files first
  const voices=db.prepare('SELECT file_path FROM meeting_voices WHERE meeting_id=?').all(m.id);
  voices.forEach(v=>{try{_fs.unlinkSync(v.file_path)}catch(e){}});
  db.prepare('DELETE FROM meeting_voices WHERE meeting_id=?').run(m.id);
  db.prepare('DELETE FROM meetings WHERE id=?').run(m.id);
  res.json({ok:true});
});
// Voice upload — accepts a raw audio binary body (audio/webm or audio/mp4)
app.post('/api/meetings/:id/voice',auth,express.raw({type:'audio/*',limit:'15mb'}),(req,res)=>{
  const m=db.prepare('SELECT id FROM meetings WHERE id=? AND user_phone=?').get(req.params.id,req.user.phone);
  if(!m)return res.status(404).json({error:'not found'});
  const buf=req.body;
  if(!Buffer.isBuffer(buf)||buf.length<200)return res.status(400).json({error:'audio body required'});
  const id=_crypto.randomBytes(10).toString('hex');
  const mime=String(req.headers['content-type']||'audio/webm').split(';')[0].toLowerCase();
  const ext=mime==='audio/mp4'?'.m4a':mime==='audio/mpeg'?'.mp3':mime==='audio/ogg'?'.ogg':'.webm';
  const fp=_path.join(MEET_VOICE_DIR,id+ext);
  try{_fs.writeFileSync(fp,buf)}catch(e){return res.status(500).json({error:'write failed'})}
  const dur=parseInt(req.query.duration||'0',10)||0;
  db.prepare('INSERT INTO meeting_voices(id,meeting_id,file_path,duration_sec,size_bytes,mime)VALUES(?,?,?,?,?,?)').run(id,m.id,fp,dur,buf.length,mime);
  db.prepare("UPDATE meetings SET updated_at=datetime('now') WHERE id=?").run(m.id);
  res.json({ok:true,voice:{id,duration_sec:dur,size_bytes:buf.length,mime}});
});
// Stream voice — auth via header OR ?token= query param so <audio src=...> works
app.get('/api/meetings/:id/voice/:vid',(req,res)=>{
  const t=req.headers['x-token']||req.query.token;
  if(!t)return res.status(401).end();
  const u=db.prepare('SELECT * FROM users WHERE token=?').get(t);
  if(!u)return res.status(401).end();
  const m=db.prepare('SELECT id FROM meetings WHERE id=? AND user_phone=?').get(req.params.id,u.phone);
  if(!m)return res.status(404).end();
  const v=db.prepare('SELECT file_path,mime FROM meeting_voices WHERE id=? AND meeting_id=?').get(req.params.vid,m.id);
  if(!v)return res.status(404).end();
  try{const buf=_fs.readFileSync(v.file_path);res.set('Content-Type',v.mime).set('Cache-Control','private, max-age=3600').send(buf)}catch(e){res.status(500).end()}
});
app.delete('/api/meetings/:id/voice/:vid',auth,(req,res)=>{
  const m=db.prepare('SELECT id FROM meetings WHERE id=? AND user_phone=?').get(req.params.id,req.user.phone);
  if(!m)return res.status(404).json({error:'not found'});
  const v=db.prepare('SELECT file_path FROM meeting_voices WHERE id=? AND meeting_id=?').get(req.params.vid,m.id);
  if(!v)return res.status(404).json({error:'not found'});
  try{_fs.unlinkSync(v.file_path)}catch(e){}
  db.prepare('DELETE FROM meeting_voices WHERE id=?').run(req.params.vid);
  res.json({ok:true});
});

// WhatsApp send endpoints disabled for closed-test phase (Twilio Sandbox requires
// each recipient to text 'join <code>' first, which would break the tester experience).
app.post('/api/send-task/:id',auth,async(req,res)=>{
  const u=db.prepare('SELECT wa_phone FROM users WHERE phone=?').get(req.user.phone);
  if(!u||!u.wa_phone)return res.status(400).json({ok:false,error:'Connect your WhatsApp from your profile first.'});
  const t=db.prepare('SELECT * FROM tasks WHERE id=? AND user_phone=?').get(req.params.id,req.user.phone);
  if(!t)return res.status(404).json({ok:false,error:'Task not found'});
  const body='📝 *'+t.title+'*'+(t.notes?'\n'+t.notes:'')+(t.due_date?'\n📅 '+fmtD(t.due_date):'')+'\n\n_Reply "done '+t.title.slice(0,20)+'" to mark complete_';
  const r=await sendWA(u.wa_phone,body);
  if(r.ok)return res.json({ok:true,sid:r.sid});
  res.status(502).json({ok:false,error:waErrorMessage(r),code:r.code});
});
app.post('/api/send-all',auth,async(req,res)=>{
  const u=db.prepare('SELECT wa_phone FROM users WHERE phone=?').get(req.user.phone);
  if(!u||!u.wa_phone)return res.status(400).json({ok:false,error:'Connect your WhatsApp from your profile first.'});
  const board=(req.body&&req.body.board)==='home'?'home':(req.body&&req.body.board)==='office'?'office':null;
  const label=board==='home'?'Home Tasks':board==='office'?'Office Tasks':'All Tasks';
  const ts=board
    ? db.prepare("SELECT * FROM tasks WHERE user_phone=? AND status!='done' AND COALESCE(board,'home')=? ORDER BY priority DESC,created_at DESC").all(req.user.phone,board)
    : db.prepare("SELECT * FROM tasks WHERE user_phone=? AND status!='done' ORDER BY priority DESC,created_at DESC").all(req.user.phone);
  if(!ts.length)return res.json({ok:true,sent:0,empty:true,label});
  const emoji=board==='home'?'🏠':board==='office'?'💼':'📋';
  let m=emoji+' *'+label+' ('+ts.length+')*\n';ts.slice(0,20).forEach((t,i)=>{m+='\n'+(i+1)+'. '+(PRI[t.priority]||'')+' '+t.title+(t.due_date?' _('+fmtD(t.due_date)+')_':'')});
  if(ts.length>20)m+='\n\n_+ '+(ts.length-20)+' more in the app_';
  const r=await sendWA(u.wa_phone,m);
  if(r.ok)return res.json({ok:true,sent:ts.length,sid:r.sid,label});
  res.status(502).json({ok:false,error:waErrorMessage(r),code:r.code});
});
app.get('/api/health',(_,res)=>res.json({status:'ok',twilio:!!tw,email:!!process.env.RESEND_API_KEY,users:db.prepare('SELECT COUNT(*)as c FROM users').get().c,tasks:db.prepare('SELECT COUNT(*)as c FROM tasks').get().c}));

