// ─── Web Audio sound effects (no library, no asset, ~free) ───
let _mgAudio=null;
function _mgSound(kind){
  try{
    if(!_mgAudio)_mgAudio=new(window.AudioContext||window.webkitAudioContext)();
    const ctx=_mgAudio,t=ctx.currentTime;
    const beep=(freq,start,dur,gain)=>{const o=ctx.createOscillator(),g=ctx.createGain();o.type='sine';o.frequency.value=freq;g.gain.setValueAtTime(gain||0.16,t+start);g.gain.exponentialRampToValueAtTime(0.001,t+start+dur);o.connect(g).connect(ctx.destination);o.start(t+start);o.stop(t+start+dur)};
    if(kind==='correct'){beep(523,0,0.16);beep(784,0.09,0.18)}
    else if(kind==='wrong'){const o=ctx.createOscillator(),g=ctx.createGain();o.type='sawtooth';o.frequency.value=200;o.frequency.linearRampToValueAtTime(110,t+0.22);g.gain.setValueAtTime(0.13,t);g.gain.exponentialRampToValueAtTime(0.001,t+0.22);o.connect(g).connect(ctx.destination);o.start(t);o.stop(t+0.22)}
    else if(kind==='levelup'){[523,659,784,1047,1319].forEach((f,i)=>beep(f,i*0.08,0.22))}
    else if(kind==='tap'){beep(680,0,0.05,0.08)}
    else if(kind==='flash'){beep(440+Math.random()*440,0,0.12,0.1)}
    else if(kind==='go'){beep(900,0,0.08);beep(900,0.1,0.08)}
    else if(kind==='paper'){
      const buf=ctx.createBuffer(1,ctx.sampleRate*0.35,ctx.sampleRate);const d=buf.getChannelData(0);for(let i=0;i<d.length;i++){const env=i<d.length*0.1?i/(d.length*0.1):i>d.length*0.7?1-(i-d.length*0.7)/(d.length*0.3):1;d[i]=(Math.random()*2-1)*0.12*env*(0.5+0.5*Math.sin(i*0.08))}
      const src=ctx.createBufferSource();src.buffer=buf;const f=ctx.createBiquadFilter();f.type='bandpass';f.frequency.value=3200;f.Q.value=1.5;src.connect(f).connect(ctx.destination);src.start(t);
    }
    else if(kind==='water'){
      // Short water drop/drip sound — like tapping a glass of water
      const dur=0.8;const buf=ctx.createBuffer(1,ctx.sampleRate*dur,ctx.sampleRate);const wd=buf.getChannelData(0);
      for(let i=0;i<wd.length;i++){const wt=i/ctx.sampleRate;
        const dropEnv=Math.exp(-wt*6);
        const drip=Math.sin(2*Math.PI*(600+400*Math.exp(-wt*8))*wt)*0.3;
        const splash=(Math.random()*2-1)*0.15*Math.exp(-wt*10);
        const ring=Math.sin(2*Math.PI*1200*wt)*0.08*Math.exp(-wt*4);
        wd[i]=dropEnv*(drip+splash+ring)}
      const ws=ctx.createBufferSource();ws.buffer=buf;
      const wlp=ctx.createBiquadFilter();wlp.type='lowpass';wlp.frequency.value=3000;
      const wg=ctx.createGain();wg.gain.value=0.5;
      ws.connect(wlp);wlp.connect(wg);wg.connect(ctx.destination);ws.start(t);
    }
    else if(kind==='tab'){beep(520,0,0.06,0.06);beep(660,0.04,0.06,0.06)}
  }catch(e){}
}
