function bookCover(id){return BOOK_COVERS[id]||null}
function openBookSummary(id,autoplay){const b=BOOK_SUMMARIES.find(x=>x.id===id);if(!b)return;S.bookReader={open:true,book:b,playing:false,rate:1};render();if(autoplay===true){requestAnimationFrame(function(){requestAnimationFrame(function(){setTimeout(function(){if(S.bookReader&&S.bookReader.book&&S.bookReader.book.id===id&&!S.bookReader.playing)bookReaderToggleTTS()},450)})})}}
// Spotify-style: tap a brief card → audio plays in the bottom mini-player
// without ever opening the big reader. Tap the mini-player to expand later.
function playBookBrief(id){
  const b=BOOK_SUMMARIES.find(x=>x.id===id);if(!b)return;
  // If this brief is already playing in the mini, just toggle pause/resume
  if(S.bkMini&&S.bkMini.book&&S.bkMini.book.id===id){bkMiniToggle();return}
  // If a different brief is playing, stop it first
  if(S.bkMini)bkMiniClose();
  if(S.bookReader&&S.bookReader.playing)_premiumStop();
  // Cancel any pending delayed-play from a previous playBookBrief call
  if(window._bkBriefTimer){clearTimeout(window._bkBriefTimer);window._bkBriefTimer=null}
  // Hidden reader state (open:false) — bookReaderToggleTTS uses S.bookReader
  // for progress callbacks but the reader UI never paints.
  S.bookReader={open:false,book:b,playing:false,rate:1};
  // Show the mini-player immediately so the user sees feedback while audio loads.
  S.bkMini={book:b,paused:false,rate:1,progress:{idx:0,total:0,line:'Loading\\u2026'}};
  render();
  window._bkBriefTimer=setTimeout(function(){
    window._bkBriefTimer=null;
    if(!S.bookReader||!S.bookReader.book||S.bookReader.book.id!==id)return;
    if(!S.bkMini)return;
    bookReaderToggleTTS();
    // Sync mini-player metadata once playback fields are populated
    if(S.bookReader.playing&&S.bkMini){
      S.bkMini.startedAt=S.bookReader.startedAt;
      S.bkMini.rate=S.bookReader.rate;
      S.bkMini.progress=S.bookReader.progress;
      render();
    }
  },350);
}
function closeBookReader(){
  // If audio is currently playing, keep it going as a persistent mini-player at the bottom
  if(S.bookReader&&S.bookReader.playing&&S.bookReader.book){
    S.bkMini={book:S.bookReader.book,startedAt:S.bookReader.startedAt,rate:S.bookReader.rate,progress:S.bookReader.progress};
    S.bookReader={open:false};
    render();
    return;
  }
  // Otherwise stop everything as before
  _killAllBookAudio();
  S.bookReader={open:false};render();
}
function bkMiniToggle(){
  if(!S.bkMini)return;
  // If audio is currently playing (window._narration active or speech synthesis), pause; else resume
  const isActive=!!(window._narration&&window._narration.audio&&!window._narration.audio.paused)||!!(window.speechSynthesis&&speechSynthesis.speaking&&!speechSynthesis.paused);
  if(isActive){
    if(window._narration&&window._narration.audio)try{window._narration.audio.pause()}catch(e){}
    if(window.speechSynthesis)try{speechSynthesis.pause()}catch(e){}
    S.bkMini.paused=true;
  } else {
    if(window._narration&&window._narration.audio)try{window._narration.audio.play()}catch(e){}
    if(window.speechSynthesis)try{speechSynthesis.resume()}catch(e){}
    S.bkMini.paused=false;
  }
  render();
}
function bkMiniClose(){_killAllBookAudio();S.bkMini=null;if(S.bookReader)S.bookReader.playing=false;render()}
function bkMiniReopen(){if(!S.bkMini||!S.bkMini.book)return;S.bookReader={open:true,book:S.bkMini.book,playing:!S.bkMini.paused,rate:S.bkMini.rate,progress:S.bkMini.progress,startedAt:S.bkMini.startedAt};S.bkMini=null;render()}
function _pickPremiumVoice(){
  if(!('speechSynthesis' in window))return null;
  const vs=speechSynthesis.getVoices();
  if(!vs||!vs.length)return null;
  // MALE voice priority — soft, warm, narrator-quality. User explicitly asked for a man's voice.
  const malePri=[
    /Microsoft\\s+(Brian|Andrew|Guy|Christopher|Eric|Davis|Jason)\\s+Online/i, // Microsoft Neural male
    /Daniel\\s+\\(Enhanced\\)/i, /Daniel\\s+\\(Premium\\)/i, /^Daniel$/i, // Apple Daniel (UK male, warm)
    /Alex\\s+\\(Enhanced\\)/i, /Alex\\s+\\(Premium\\)/i, /^Alex$/i,         // Apple Alex (US male, classic narrator)
    /Tom\\s+\\(Enhanced\\)/i, /^Tom$/i,
    /Aaron\\s+\\(Enhanced\\)/i, /^Aaron$/i,
    /Fred\\s+\\(Enhanced\\)/i, /^Fred$/i,
    /Oliver\\s+\\(Enhanced\\)/i, /^Oliver$/i,
    /Google\\s+UK\\s+English\\s+Male/i, // Chrome on desktop
    /Microsoft\\s+(David|Mark|George|James)\\s+/i, // Microsoft legacy male
    // Android voices — names like "en-us-x-iom-local", "en-us-x-tpc-network"
    /en-us-x-(iom|tpc|tpd|iol|iob)/i, // Android male voice IDs
  ];
  for(const re of malePri){const v=vs.find(x=>x.name&&re.test(x.name));if(v)return v}
  // Heuristic — anything with "male" in the name and English language
  const heur=vs.find(x=>x.lang&&x.lang.startsWith('en')&&/male/i.test(x.name||'')&&!/female/i.test(x.name||''));
  if(heur)return heur;
  // On Android, prefer a non-default voice (second or third English voice tends to differ from default)
  const enVoices=vs.filter(x=>x.lang&&/^en/i.test(x.lang));
  if(enVoices.length>1)return enVoices[1]; // skip default (index 0, usually female)
  // Last-resort fallback to any English voice
  return enVoices[0]||vs[0];
}
// Nuclear kill: stops ALL book/summary audio — TTS queue, static audio, pending timers, speechSynthesis
function _killAllBookAudio(){
  if(window._bkBriefTimer){clearTimeout(window._bkBriefTimer);window._bkBriefTimer=null}
  // Mark playback as dead BEFORE stopping audio — prevents onerror/catch handlers from
  // triggering _fallbackBookTTS() which starts a NEW female-voice TTS after the kill.
  if(S.bookReader)S.bookReader.playing=false;
  _premiumStop();
  if(window._fbKeepalive){clearInterval(window._fbKeepalive);window._fbKeepalive=null}
  // Nullify event handlers BEFORE setting src='' — setting src='' fires onerror which
  // was calling _fallbackBookTTS(), starting a new TTS session with the wrong voice.
  const bna=document.getElementById('bk-narr-audio');if(bna){try{bna.onerror=null;bna.onended=null;bna.ontimeupdate=null;bna.pause();bna.src=''}catch(e){}}
  if(S.bookReader&&S.bookReader._staticAudio){try{S.bookReader._staticAudio.onerror=null;S.bookReader._staticAudio.onended=null;S.bookReader._staticAudio.ontimeupdate=null;S.bookReader._staticAudio.pause();S.bookReader._staticAudio.src=''}catch(e){}}
  try{if(window.speechSynthesis){speechSynthesis.cancel()}}catch(e){}
  setTimeout(function(){try{if(window.speechSynthesis)speechSynthesis.cancel()}catch(e){}},80);
}
// Chunked TTS — splits long text into sentence groups so Chrome doesn't time out at ~15s
// Plus a keepalive pause/resume hack that fights the well-known Web Speech cutoff bug
function _ttsStop(){if(window._ttsQueue)window._ttsQueue.cancelled=true;window._ttsQueue=null;if(window._ttsKeepalive){clearInterval(window._ttsKeepalive);window._ttsKeepalive=null}try{speechSynthesis.cancel()}catch(e){}setTimeout(()=>{try{speechSynthesis.cancel()}catch(e){}},60)}
// Narration — all voice is browser TTS (speechSynthesis). Static MP3s are used
// for books via /api/book-audio/:id and meditations via /api/audio/:id.
// _premiumNarrate is kept as the name for backward compat — it just calls browser TTS.
async function _premiumNarrate(text,opts,onAllDone,onProgress){
  _premiumStop();
  return _browserTtsSpeak(text,opts,onAllDone,onProgress);
}
function _premiumStop(){_ttsStop();if(window._narration){window._narration.cancelled=true;if(window._narration.audio){try{window._narration.audio.pause();window._narration.audio.src=''}catch(e){}}window._narration=null}}
// _ttsSpeak is the public entry point for every TTS call across the app.
// Routes through _premiumNarrate so callers get browser TTS,
// which chunks text for the browser's speechSynthesis. Old code that called _ttsSpeak still works
// (Voice trainer drills, game celebrations, vocabulary cards, lesson runner, etc.).
function _ttsSpeak(text,opts,onAllDone,onProgress){return _premiumNarrate(text,opts,onAllDone,onProgress)}
// Browser chunked TTS — the primary voice engine for non-book narration.
// All public callers should use _ttsSpeak (the dispatcher alias defined below) so they get the
// premium voice automatically when configured.
function _browserTtsSpeak(text,opts,onAllDone,onProgress){
  if(!('speechSynthesis' in window))return false;
  _ttsStop();
  const sentences=(text.match(/[^.!?\\u2026]+[.!?\\u2026]+["\\u2019\\u201d)]?\\s*/g))||[text];
  const chunks=[];let cur='';
  for(const s of sentences){
    if((cur+s).length>180){if(cur)chunks.push(cur.trim());cur=s}
    else cur+=s;
  }
  if(cur.trim())chunks.push(cur.trim());
  if(!chunks.length)return false;
  const pickedVoice=_pickPremiumVoice(); // cache once so voice stays consistent across chunks
  const queue={chunks,idx:0,opts:opts||{},onAllDone,onProgress,cancelled:false,voice:pickedVoice};
  window._ttsQueue=queue;
  function speakNext(){
    if(queue.cancelled)return;
    if(queue.idx>=queue.chunks.length){
      if(window._ttsKeepalive){clearInterval(window._ttsKeepalive);window._ttsKeepalive=null}
      if(typeof onAllDone==='function')onAllDone();
      return;
    }
    if(typeof onProgress==='function')try{onProgress(queue.idx,queue.chunks.length,queue.chunks[queue.idx])}catch(e){}
    const u=new SpeechSynthesisUtterance(queue.chunks[queue.idx]);
    u.rate=queue.opts.rate||1;u.pitch=queue.opts.pitch||1.0;u.volume=queue.opts.volume||1.0;
    const v=queue.voice;if(v){u.voice=v;u.lang=v.lang||'en-US'}
    u.onend=function(){if(queue.cancelled)return;queue.idx++;speakNext()};
    u.onerror=function(){if(queue.cancelled)return;queue.idx++;speakNext()};
    try{speechSynthesis.speak(u)}catch(e){if(queue.cancelled)return;queue.idx++;speakNext()}
  }
  if(window._ttsKeepalive)clearInterval(window._ttsKeepalive);
  window._ttsKeepalive=setInterval(function(){try{if(speechSynthesis.speaking&&!speechSynthesis.paused){speechSynthesis.pause();speechSynthesis.resume()}}catch(e){}},10000);
  speakNext();
  return true;
}
// Structured narration — assembles a full ~12-15 min audio experience from the book's parts:
// title, why-pitch, each numbered insight, then the long summary. Slow male narrator pace.
function _bookFullNarration(book){
  // Clean chapter-wise audiobook narration.
  // No "take a breath", no meditation-style filler — this is a book brief,
  // not a guided meditation. Each chapter is announced by number + title,
  // then the body, with elaboration from the summary woven in.
  const parts=[];
  // Opening — title, author, why-line. No instructions to the listener.
  parts.push(book.title+', by '+book.author+'.');
  if (book.why) parts.push(book.why);
  // Pre-segment summary by sentences for elaboration mining
  const summSentences=(book.summary||'').replace(/\\u2026/g,'...').split(/(?<=[.!?])\\s+/).filter(s=>s.trim().length>20);
  const used=new Set();
  function findElab(title,body){
    const titleWords=title.toLowerCase().match(/\\b[a-z]{4,}\\b/g)||[];
    const bodyWords=body.toLowerCase().match(/\\b[a-z]{4,}\\b/g)||[];
    const score=(s)=>{
      const sl=s.toLowerCase();let n=0;
      titleWords.forEach(w=>{if(sl.includes(w))n+=3});
      bodyWords.forEach(w=>{if(sl.includes(w))n+=1});
      return n;
    };
    const ranked=summSentences
      .map((s,i)=>({s,i,score:score(s)}))
      .filter(x=>x.score>0&&!used.has(x.i))
      .sort((a,b)=>b.score-a.score)
      .slice(0,2);
    ranked.forEach(x=>used.add(x.i));
    return ranked.map(x=>x.s);
  }
  // Chapters — numbered headings + body + woven elaboration. No transitional fluff.
  book.insights.forEach((it,i)=>{
    parts.push('Chapter '+(i+1)+'. '+it[0]+'.');  // "Chapter 1. Nose, not mouth."
    parts.push(it[1]);                              // chapter body
    const elab=findElab(it[0],it[1]);
    if(elab.length){parts.push(elab.join(' '))}
  });
  // Closing — any unused summary sentences as a final chapter, no exhortations.
  const leftover=summSentences.filter((_,i)=>!used.has(i));
  if(leftover.length){
    parts.push('Closing notes.');
    parts.push(leftover.slice(0,3).join(' '));
  }
  parts.push('That concludes '+book.title+'.');
  return parts.join('  ').replace(/\\\\u2019/g,"'").replace(/\\\\u2014/g,', ').replace(/\\u2026/g,'...').replace(/\\s+/g,' ').trim();
}
function bookReaderToggleTTS(){
  const r=S.bookReader;if(!r||!r.book)return;
  if(r.playing){_killAllBookAudio();r.playing=false;r.progress=null;render();return}
  r.startedAt=Date.now();r.progress={idx:0,total:1,line:'Loading narration...'};r.playing=true;render();
  const onDone=function(){const cur=S.bookReader;if(!cur||!cur.book)return;cur.playing=false;cur.completed=true;cur.progress=null;render();try{api('/book-streak',{method:'POST',body:JSON.stringify({seconds:r.book.mins*60})}).then(()=>loadBookStreak())}catch(e){}toast('\\u2728 Summary complete \\u2014 streak +1')};
  const onProgress=function(idx,total,line){const cur=S.bookReader;if(!cur||!cur.book)return;cur.progress={idx,total,line};const bar=document.getElementById('bkProgFill');const txt=document.getElementById('bkProgText');const pct=document.getElementById('bkProgPct');const t=document.getElementById('bkProgTime');if(bar)bar.style.transform='scaleX('+(idx/total)+')';if(txt)txt.textContent=String(line||'').slice(0,90)+(String(line||'').length>90?'...':'');if(pct)pct.textContent=Math.round((idx/total)*100)+'%';if(t){const elapsed=Math.floor((Date.now()-(cur.startedAt||Date.now()))/1000);t.textContent=Math.floor(elapsed/60)+':'+String(elapsed%60).padStart(2,'0')}};
  const bid=r.book.id;
  fetch('/api/book-audio/'+encodeURIComponent(bid)+'?token='+encodeURIComponent(token),{method:'HEAD'}).then(function(resp){
    if(!resp.ok)throw new Error('no static');
    let a=document.getElementById('bk-narr-audio');
    if(!a){a=document.createElement('audio');a.id='bk-narr-audio';a.preload='auto';document.body.appendChild(a)}
    a.src='/api/book-audio/'+encodeURIComponent(bid)+'?token='+encodeURIComponent(token);
    a.playbackRate=Math.max(0.5,Math.min(2.0,r.rate||1.0));
    r._staticAudio=a;
    a.ontimeupdate=function(){if(a.duration){onProgress(Math.floor(a.currentTime),Math.ceil(a.duration),r.book.title)}};
    a.onended=function(){r._staticAudio=null;if(r.playing)onDone()};
    a.onerror=function(){r._staticAudio=null;if(!r.playing)return;_fallbackBookTTS(r,onDone,onProgress)};
    const p=a.play();if(p&&p.catch)p.catch(function(){if(!r.playing)return;_fallbackBookTTS(r,onDone,onProgress)});
  }).catch(function(){if(!r.playing)return;_fallbackBookTTS(r,onDone,onProgress)});
}
function _fallbackBookTTS(r,onDone,onProgress){
  // Guard: don't start TTS fallback if playback was stopped by user (close/X button).
  // Without this, onerror/catch handlers from the killed audio element trigger a NEW
  // browser TTS session, which is the "lady voice starts speaking" bug on Android.
  if(!r||!r.playing)return;
  if(!S.bookReader||!S.bookReader.playing)return;
  const baseRate=r.rate||0.78;
  const fullText=_bookFullNarration(r.book);

  const ok=_premiumNarrate(fullText,{rate:baseRate,pitch:0.95,volume:1.0},onDone,onProgress);
  if(ok===false){r.playing=false;render()}
}
function bookReaderSpeed(){const r=S.bookReader;if(!r)return;const cycle={0.78:0.95,0.95:1.0,1.0:1.1,1.1:1.25,1.25:1.5,1.5:0.78};const cur=r.rate||1.0;r.rate=cycle[cur]||1.0;if(r._staticAudio){r._staticAudio.playbackRate=Math.max(0.5,Math.min(2.0,r.rate))}else if(r.playing){_ttsStop();r.playing=false;bookReaderToggleTTS()}render()}

