  if(!_otpEvidence){try{const _raw=localStorage.getItem('tf_login_state');if(_raw){const _d=JSON.parse(_raw);if(_d&&_d.step==='otp'&&_d.ts&&Date.now()-_d.ts<3600000)_otpEvidence=true}}catch(e){}}
  if(_otpEvidence){try{restoreLoginState()}catch(e){}S.loginStep='otp';if(!S.loginEmail){try{S.loginEmail=localStorage.getItem('tf_email')||''}catch(e){}}if(!S.loginSentTo)S.loginSentTo=S.loginEmail||S.loginPhone||''}
