    const dur=b2-a;
    selHTML='<div class="schX-sel" style="top:'+top+'px;height:'+ht+'px">'
      +'<div class="schX-sel-head">'+_minToLabel(a)+' \\u2192 '+_minToLabel(b2)+' \\u00B7 '+(dur>=60?Math.floor(dur/60)+'h '+(dur%60?(dur%60)+'m':''):dur+'m')+'</div>'
